import{c as a,Q as r,j as o,m as s}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse(`{"title":"How do I change a user's portal role?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/change-user-role.md","filePath":"guide/recipes/portal/change-user-role.md","lastUpdated":1779094756000}`),t={name:"guide/recipes/portal/change-user-role.md"};function n(l,e,i,c,d,h){return r(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="how-do-i-change-a-user-s-portal-role" tabindex="-1">How do I change a user&#39;s portal role? <a class="header-anchor" href="#how-do-i-change-a-user-s-portal-role" aria-label="Permalink to &quot;How do I change a user&#39;s portal role?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> can assign any role (except Owner — use <em>transfer ownership</em>).<br><strong>Admin</strong> can assign Billing, Viewer, or Member only.</p></div><p>Portal roles control what someone can do <em>across</em> the customer (Users, Billing, Settings). Tenant roles are separate.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Users</strong> in the sidebar.</li><li>Click the row of the user you want to change.</li><li>In the expanded panel, change the <strong>Portal Role</strong> dropdown.</li><li>The change saves automatically.</li></ol><div class="warning custom-block"><p class="custom-block-title">Restrictions</p><ul><li>Admins can&#39;t change another Admin&#39;s role — only the Owner can.</li><li>No one can change the Owner&#39;s role from the dropdown. Use <a href="./transfer-ownership">transfer ownership</a> instead.</li></ul></div><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The user&#39;s role updates immediately. Their next page load reflects the new permissions — sidebar items they no longer have access to disappear, and protected actions get hidden.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./promote-to-admin">How do I promote someone to Admin?</a></li><li><a href="./transfer-ownership">How do I transfer ownership of my customer?</a></li><li><a href="./../../concepts/roles-and-permissions">Roles &amp; Permissions reference</a></li></ul>',10)])])}const u=a(t,[["render",n]]);export{m as __pageData,u as default};
